cat > /tmp/find_fix_files.py << 'EOF'
import os
import re

# Search for all Python files that contain any of the fix-related code patterns
fix_patterns = [
    r'_clear_nodes',
    r'_cleanup_output_graph',
    r'output_graph_for_cleanup',
    r'DynamoTracerOutput.*error\s*=\s*True',
    r'tracked_fakes\s*=\s*None',
]

files_with_fix = {}
search_dirs = ['/workspace/torch/_dynamo', '/workspace/torch/fx']

for search_dir in search_dirs:
    for root, dirs, files in os.walk(search_dir):
        # Skip __pycache__ and .git directories
        dirs[:] = [d for d in dirs if d not in ['__pycache__', '.git']]

        for file in files:
            if file.endswith('.py'):
                filepath = os.path.join(root, file)
                try:
                    with open(filepath, 'r') as f:
                        content = f.read()

                    found_patterns = []
                    for pattern in fix_patterns:
                        if re.search(pattern, content):
                            found_patterns.append(pattern)

                    if found_patterns:
                        files_with_fix[filepath] = found_patterns
                except Exception:
                    pass

print("Files containing fix-related code:")
print("=" * 80)
for filepath in sorted(files_with_fix.keys()):
    rel_path = filepath.replace('/workspace/', '')
    print(f"\n📄 {rel_path}")
    for pattern in files_with_fix[filepath]:
        print(f"   - {pattern}")

print(f"\nTotal files with fix code: {len(files_with_fix)}")
EOF
python3 /tmp/find_fix_files.py

